SELECT COUNT(*) as total FROM factures_electroniques WHERE tenant_id = '{{ $json.tenantId }}'
{% if $json.profil %}
  AND profil = '{{ $json.profil }}'
{% endif %}
{% if $json.statut %}
  AND statut = '{{ $json.statut }}'
{% endif %}

SELECT fe.id, fe.facture_id, fe.format, fe.profil, fe.statut, fe.date_generation, fe.date_transmission, fe.plateforme, fe.identifiant_ppf, f.numero_facture, f.montant_ttc, c.nom as client_nom FROM factures_electroniques fe LEFT JOIN factures f ON fe.facture_id = f.id LEFT JOIN clients c ON f.client_id = c.id WHERE fe.tenant_id = '{{ $json.tenantId }}'
{% if $json.profil %}
  AND fe.profil = '{{ $json.profil }}'
{% endif %}
{% if $json.statut %}
  AND fe.statut = '{{ $json.statut }}'
{% endif %}
ORDER BY fe.date_generation DESC
LIMIT {{ $json.limit }} OFFSET {{ ($json.page - 1) * $json.limit }}

